import { useEffect, useCallback } from 'react';
import { Linking, Alert } from 'react-native';
import { useNavigation } from '@react-navigation/native';

const ALLOWED_SCHEMES = ['myapp'];
const ALLOWED_HOSTS = ['profile', 'payment', 'settings', 'product'];

const ROUTE_CONFIG = {
  profile: {
    screen: 'Profile',
    params: ['id'],
    validators: {
      id: (value) => /^\d+$/.test(value)
    }
  },
  payment: {
    screen: 'Payment',
    params: ['action', 'orderId'],
    validators: {
      action: (value) => ['confirm', 'cancel', 'view'].includes(value),
      orderId: (value) => /^[a-zA-Z0-9-_]+$/.test(value)
    }
  },
  settings: {
    screen: 'Settings',
    params: ['section'],
    validators: {
      section: (value) => ['account', 'privacy', 'notifications'].includes(value)
    }
  },
  product: {
    screen: 'ProductDetail',
    params: ['id', 'variant'],
    validators: {
      id: (value) => /^\d+$/.test(value),
      variant: (value) => !value || /^[a-zA-Z0-9-_]+$/.test(value)
    }
  }
};

const parseDeepLink = (url) => {
  try {
    const urlObj = new URL(url);
    const scheme = urlObj.protocol.replace(':', '');
    const host = urlObj.hostname || urlObj.pathname.split('/')[0];
    const pathParts = urlObj.pathname.split('/').filter(part => part);
    
    if (urlObj.hostname) {
      pathParts.shift();
    }

    const searchParams = {};
    urlObj.searchParams.forEach((value, key) => {
      searchParams[key] = value;
    });

    return {
      scheme,
      host,
      path: pathParts,
      params: searchParams,
      raw: url
    };
  } catch (error) {
    console.error('Failed to parse deep link:', error);
    return null;
  }
};

const validateScheme = (scheme) => {
  return ALLOWED_SCHEMES.includes(scheme);
};

const validateHost = (host) => {
  return ALLOWED_HOSTS.includes(host);
};

const validateParams = (host, pathParts, queryParams) => {
  const config = ROUTE_CONFIG[host];
  if (!config) {
    return { valid: false, error: 'Unknown route configuration' };
  }

  const allParams = {};
  
  config.params.forEach((paramName, index) => {
    if (pathParts[index]) {
      allParams[paramName] = pathParts[index];
    }
  });

  Object.keys(queryParams).forEach(key => {
    if (config.params.includes(key)) {
      allParams[key] = queryParams[key];
    }
  });

  for (const [paramName, validator] of Object.entries(config.validators)) {
    const value = allParams[paramName];
    
    if (value && !validator(value)) {
      return { 
        valid: false, 
        error: `Invalid parameter: ${paramName}`,
        param: paramName 
      };
    }
  }

  return { valid: true, params: allParams };
};

const sanitizeParams = (params) => {
  const sanitized = {};
  
  for (const [key, value] of Object.entries(params)) {
    if (typeof value === 'string') {
      sanitized[key] = value.trim().substring(0, 1000);
    } else {
      sanitized[key] = value;
    }
  }
  
  return sanitized;
};

export const useDeepLinkHandler = (options = {}) => {
  const navigation = useNavigation();
  const {
    onError = (error) => Alert.alert('Invalid Link', error),
    onSuccess = () => {},
    enableLogging = false
  } = options;

  const handleDeepLink = useCallback((url) => {
    if (enableLogging) {
      console.log('Processing deep link:', url);
    }

    const parsed = parseDeepLink(url);
    
    if (!parsed) {
      onError('Invalid URL format');
      return false;
    }

    if (!validateScheme(parsed.scheme)) {
      onError('Invalid URL scheme. Only myapp:// links are allowed.');
      return false;
    }

    if (!validateHost(parsed.host)) {
      onError('Invalid or unauthorized route.');
      return false;
    }

    const validation = validateParams(parsed.host, parsed.path, parsed.params);
    
    if (!validation.valid) {
      onError(validation.error || 'Invalid parameters');
      return false;
    }

    const config = ROUTE_CONFIG[parsed.host];
    const sanitizedParams = sanitizeParams(validation.params);

    try {
      navigation.navigate(config.screen, sanitizedParams);
      onSuccess({ screen: config.screen, params: sanitizedParams });
      
      if (enableLogging) {
        console.log('Navigation successful:', config.screen, sanitizedParams);
      }
      
      return true;
    } catch (error) {
      console.error('Navigation error:', error);
      onError('Failed to navigate to the requested screen');
      return false;
    }
  }, [navigation, onError, onSuccess, enableLogging]);

  useEffect(() => {
    const handleInitialURL = async () => {
      try {
        const initialUrl = await Linking.getInitialURL();
        if (initialUrl) {
          handleDeepLink(initialUrl);
        }
      } catch (error) {
        console.error('Error getting initial URL:', error);
      }
    };

    handleInitialURL();

    const subscription = Linking.addEventListener('url', ({ url }) => {
      handleDeepLink(url);
    });

    return () => {
      subscription.remove();
    };
  }, [handleDeepLink]);

  return { handleDeepLink };
};

export const DeepLinkHandler = ({ children, onError, onSuccess, enableLogging }) => {
  useDeepLinkHandler({ onError, onSuccess, enableLogging });
  return children;
};

export const createDeepLink = (host, params = {}) => {
  const config = ROUTE_CONFIG[host];
  
  if (!config) {
    throw new Error(`Unknown host: ${host}`);
  }

  const pathParts = [];
  const queryParams = new URLSearchParams();

  config.params.forEach(paramName => {
    const value = params[paramName];
    
    if (value !== undefined && value !== null) {
      const validator = config.validators[paramName];
      
      if (validator && !validator(String(value))) {
        throw new Error(`Invalid parameter value for ${paramName}`);
      }

      if (pathParts.length < config.params.length - 1) {
        pathParts.push(encodeURIComponent(value));
      } else {
        queryParams.append(paramName, value);
      }
    }
  });

  let url = `myapp://${host}`;
  
  if (pathParts.length > 0) {
    url += '/' + pathParts.join('/');
  }

  const queryString = queryParams.toString();
  if (queryString) {
    url += '?' + queryString;
  }

  return url;
};

export const isValidDeepLink = (url) => {
  const parsed = parseDeepLink(url);
  
  if (!parsed) return false;
  if (!validateScheme(parsed.scheme)) return false;
  if (!validateHost(parsed.host)) return false;
  
  const validation = validateParams(parsed.host, parsed.path, parsed.params);
  return validation.valid;
};

export { ALLOWED_SCHEMES, ALLOWED_HOSTS, ROUTE_CONFIG };